example_bad:
trait Builder {
    fn build(&self) -> String;
}

struct HtmlBuilder;

impl Builder for HtmlBuilder {
    fn build(&self) -> &str { // Error: return type mismatch
        "<html></html>"
    }
}

fixes.code:
impl Builder for HtmlBuilder {
    fn build(&self) -> String {
        String::from("<html></html>")
    }
}

trait Builder {
    type Output;
    fn build(&self) -> Self::Output;
}

impl Builder for HtmlBuilder {
    type Output = String;
    fn build(&self) -> String {
        String::from("<html></html>")
    }
}
